import java.io.File;
import java.util.HashMap;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

public class XMLParser {
  public static Map<String, String> parseXML(File xmlFile) throws Exception {
    DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
    factory.setValidating(true);
    factory.setNamespaceAware(true);
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
    DocumentBuilder builder = factory.newDocumentBuilder();
    Document document = builder.parse(xmlFile);
    Element rootElement = document.getDocumentElement();
    NodeList configurationSettings = rootElement.getElementsByTagName("configurationSetting");
    Map<String, String> settingsMap = new HashMap<>();
    for (int i = 0; i < configurationSettings.getLength(); i++) {
      Element settingElement = (Element) configurationSettings.item(i);
      String key = settingElement.getAttribute("key");
      String value = settingElement.getTextContent();
      settingsMap.put(key, value);
    }
    return settingsMap;
  }
}